import{_ as c,o as h,c as d,a6 as u,cc as m,nk as g,nl as y,cf as f,cg as b,ab as k,ch as w,ci as v,cj as _,ck as T,cl as S,cm as I,c6 as P,cn as C,co as t,cp as x,cq as s,cr as Y,cU as N,cV as q,cW as E,cX as A,ad as e,cY as n,cZ as F,c_ as M,c$ as O,d0 as L,d1 as D,d2 as K,d3 as i,d4 as o,d5 as r,d6 as l,d7 as p,d8 as G,d9 as V,da as W,db as R,dc as B,dd as H,de as z,cJ as U,df as j,dg as $,dh as J,di as X,dj as Q,dk as Z,dl as tt,dm as et,dn as ot,dp as at,dq as st,dr as nt,ds as it,dt as rt,du as lt,dv as pt}from"./chunks/framework.UYVGz2W_.js";const bt=JSON.parse('{"title":"Create a SHOTS-only Production","description":"","frontmatter":{},"headers":[],"relativePath":"short-shot/index.md","filePath":"short-shot/index.md"}'),ct={name:"short-shot/index.md"};function ht(dt,a,ut,mt,gt,yt){return h(),d("div",null,[...a[0]||(a[0]=[u('<h1 id="create-a-shots-only-production" tabindex="-1">Create a SHOTS-only Production <a class="header-anchor" href="#create-a-shots-only-production" aria-label="Permalink to “Create a SHOTS-only Production”">​</a></h1><p>Now that you have designed your workflow in Kitsu and invited more people, it&#39;s time to create your Production.</p><p>Click on the <strong>Create a new production</strong> button.</p><p><img src="'+m+'" alt="Create a production"></p><p>Enter your production name, select <strong>only shots</strong> as the <strong>type</strong>, and select the style that best suits your Production.</p><p>Then, you must fill in technical information, such as the number of FPS, the Ration, and the Resolution.</p><p>All these data will be used when Kitsu re-encodes the video previews uploaded.</p><p>Then, you need to define your Production&#39;s start and end dates.</p><p><img src="'+g+'" alt="Add a production"></p><p>You need to select your shots workflow (Task Type) (3) and your validation process (Task Status) (4),</p><p><img src="'+y+'" alt="Add a production Pipeline"></p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>To create your <strong>Production Workflow</strong>, you will select Task Types from the Global Library.</p><p>If you realize you missed some Task Types, you can create them later.</p><p>See the <a href="./../configure-kitsu/index.html#studio-workflows">Studio Workflow</a> section.</p></div><p>Then, 5 is the option parts. If you already have a spreadsheet with your shot.</p><p>See the <strong>import CSV</strong> section for more details.</p><p>[Import shot](#create-shots-from-an-edl-file</p><p>Validate everything with the <img src="'+f+'" alt="All done"> button.</p><h2 id="introduction-to-the-kitsu-global-page" tabindex="-1">Introduction to the Kitsu Global Page <a class="header-anchor" href="#introduction-to-the-kitsu-global-page" aria-label="Permalink to “Introduction to the Kitsu Global Page”">​</a></h2><p>Welcome to Kitsu&#39;s global asset page.</p><p>Let&#39;s take a look around.</p><p><img src="'+b+'" alt="Presentation of the global page"></p><p>On the top part (1), you have the <strong>global navigation</strong>, which is always visible throughout all the production pages.</p><p><strong>From left to right:</strong></p><h3 id="main-menu" tabindex="-1">Main Menu <a class="header-anchor" href="#main-menu" aria-label="Permalink to “Main Menu”">​</a></h3><p>By clicking on the top left button, Kitsu<img src="'+k+'" alt="Main menu button"> (or your Studio logo), you will open the <strong>Main Menu</strong>.</p><p>On the Main Menu, you will find direct access to your assigned tasks, productions, global and team schedules, the workflow customization page, and the Kitsu settings.</p><details class="details custom-block"><summary>Main Menu Details</summary><p><strong>WORKSPACE</strong></p><ul><li>My Tasks: your assigned tasks</li><li>My Checks: All the tasks with status <strong>Is Feedback Request</strong> depending on your department(s)</li><li>My Productions: Get back to the selection on the production page.</li></ul><p><strong>STUDIO</strong></p><ul><li>Productions</li><li>People</li><li>Timesheets</li><li>Main Schedule</li><li>Team Schedule</li><li>All tasks</li><li>News Feed</li><li>Entity Search</li></ul><p><strong>ADMIN</strong></p><ul><li>Departments</li><li>Task Types</li><li>Asset Types</li><li>Custom Actions</li><li>Automation</li><li>3D Backgrounds</li><li>Bots</li><li>Settings</li><li>Logs</li></ul><div class="warning custom-block"><p class="custom-block-title">Permission Visibility</p><p>The WORKSPACE section is enabled for all permissions except My Checks, which artists do not see.</p><p>Artist (and above) can also see their own <strong>Timesheets</strong>, and have access to the <strong>Entity Search</strong></p></div></details><h3 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to “Navigation”">​</a></h3><p>You will see the navigation dropdown menu on the right of the main menu icon.</p><p><img src="'+w+'" alt="Presentation of the global page"></p><p>You can choose between Production. The name of the actual Production and page are always displayed.</p><p>You can use the dropdown menu to navigate from Production to Production (if you have several).</p><p>Once you have selected a production, the next dropdown menu will help you navigate through the different pages of this Production.</p><details class="details custom-block"><summary>Navigation details</summary><p>The first section is about the tracking of your tasks</p><ul><li>Shots</li><li>Sequence</li><li>Edits (If you have created specific tasks)</li></ul><p>The second section is more about the side of the Production</p><ul><li>Concepts</li><li>Playlists</li><li>News feed</li></ul><p>The third section is about statistics</p><ul><li>Sequence Stats</li></ul><p>The fourth section is related to Team Management</p><ul><li>Schedule</li><li>Quotas</li><li>Team</li></ul><p>The fifth section is about the settings of your Production</p><ul><li>Settings</li></ul><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>You start with the asset page, but you can change your production homepage to other entities (see setting page)</p></div></details><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>If you realize you need an extra level of navigation, such as <strong>Episodes</strong>, you need to change your production Type to a <strong>TV Show</strong>.</p><p>If, on the contrary, you realize you need the assets instead of the Only Shots, you need to switch your production type from Only Shots to Short.</p></div><h3 id="global-search-news-notification-and-documentation" tabindex="-1">Global Search, News, Notification and Documentation <a class="header-anchor" href="#global-search-news-notification-and-documentation" aria-label="Permalink to “Global Search, News, Notification and Documentation”">​</a></h3><p>You have the global search on the right of the navigation dropdown menu. It&#39;s a quick access search that will display the four first results. If you need more results and filtering options, see the <strong>Entity Search</strong> page.</p><p>The next icon <img src="'+v+'" alt="News"> is a direct link to our news and feedback page.</p><p>You can see all the new features with an animated gif and also add suggestions about the next feature you want to see in Kitsu.</p><p>Next, the bell icon <img src="'+_+'" alt="Notification"> displays your notifications (assignments, comments, tags). The number of unread notifications will be shown on the bell icon. There are various filters to help you stay on top of updates and revisit important ones when needed. You can easily mark notifications as read or unread or quickly filter by watching/non-watching to focus on what matters most and declutter your feed.</p><p>The last icon before your avatar is the documentation button. <img src="'+T+'" alt="documentation button">, that you are reading right now!</p><h3 id="personal-settings" tabindex="-1">Personal Settings <a class="header-anchor" href="#personal-settings" aria-label="Permalink to “Personal Settings”">​</a></h3><p>You can click on your avatar to open your menu (setting, documentation, etc.).</p><p><img src="'+S+'" alt="Profile enlarged">.</p><h2 id="the-tasks-spreadsheet" tabindex="-1">The Tasks Spreadsheet <a class="header-anchor" href="#the-tasks-spreadsheet" aria-label="Permalink to “The Tasks Spreadsheet”">​</a></h2><h3 id="entity-spreadsheet" tabindex="-1">Entity spreadsheet <a class="header-anchor" href="#entity-spreadsheet" aria-label="Permalink to “Entity spreadsheet”">​</a></h3><p>The second part of the screen is common to all the entities (asset, shot, sequence, Edit). This is the global tasks spreadsheet.</p><p>Here, you see the status, assignation, priority, etc, for each task.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>The first line and column header of the spreadsheet always appear at the top of the page, even if you scroll down.</p><p>You can also <strong>Stick</strong> other columns to keep them visible at all times.</p></div><h3 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to “Filters”">​</a></h3><p>The first element on the left is the filter box. You can type anything you want for simple filtering, sequence, asset type, etc.</p><p>If you need more advanced filtering, please use the filter builder button.</p><p><img src="'+I+'" alt="Filter Builder"></p><p>You can then save all the filters and use them as your pages.</p><h3 id="simplify-the-display" tabindex="-1">Simplify the display <a class="header-anchor" href="#simplify-the-display" aria-label="Permalink to “Simplify the display”">​</a></h3><p>On the right part of the screen, there are some buttons (from left to right) to hide or display the assignation, hide or display the extra column, enlarge or reduce the thumbnail, <img src="'+P+'" alt="display and Hide option"></p><h3 id="import-export" tabindex="-1">Import / Export <a class="header-anchor" href="#import-export" aria-label="Permalink to “Import / Export”">​</a></h3><p>batch import thumbnail <img src="'+C+'" alt="batch import thumbnail">, and finally import <img src="'+t+'" alt="Import button"> or export <img src="'+x+'" alt="export button"> data.</p><h3 id="metadata-column" tabindex="-1">Metadata column <a class="header-anchor" href="#metadata-column" aria-label="Permalink to “Metadata column”">​</a></h3><p>Below, you have the name of the column. the (+) next to <strong>Name</strong> <img src="'+s+'" alt="Add metadata column"> is here to create a new metadata column. Then, you have the name of the task type column.</p><h3 id="customize-the-view" tabindex="-1">Customize the view <a class="header-anchor" href="#customize-the-view" aria-label="Permalink to “Customize the view”">​</a></h3><p>On the far right of the screen, next to the scroll bar, is the option to hide and display a text column</p><p><img src="'+Y+'" alt="Display/hide text column">.</p><h3 id="sum-up-of-your-view" tabindex="-1">Sum-up of your view <a class="header-anchor" href="#sum-up-of-your-view" aria-label="Permalink to “Sum-up of your view”">​</a></h3><p>The last part (4), at the bottom of the screen, is the sum-up of your displayed page. It means the sum-up will update if you filter the page.</p><p>You can see the number of elements (assets or shots), the total number of estimated days, and the total number of days already spent.</p><h2 id="create-a-shot" tabindex="-1">Create a Shot <a class="header-anchor" href="#create-a-shot" aria-label="Permalink to “Create a Shot”">​</a></h2><h3 id="create-your-first-shot" tabindex="-1">Create your first shot <a class="header-anchor" href="#create-your-first-shot" aria-label="Permalink to “Create your first shot”">​</a></h3><p>It&#39;s time to create <strong>shots</strong> for your Production.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Shots are linked to Sequences in Kitsu. This means you need to first create a sequence and then populate this sequence with shots.</p></div><p>You need to go to the <strong>Shots</strong> page: you can use the dropdown menu and click on the <strong>SHOTS</strong>.</p><p><img src="'+N+'" alt="Drop down menu shot"></p><p>Click on the <strong>Add shots</strong> button to start with the shot creation.</p><p><img src="'+q+'" alt="First add shots"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>When you create a shot, the task workflow you have designed will be applied, and all the tasks will be created at the same time as the shot.</p></div><p>A new pop-up opens for the creation of the shots. You can now create the sequences and the shots.</p><p>Enter the first sequence, for instance, sq01, then <strong>add</strong>.</p><p>Now, you can see your sequence has been created. To add shots to this sequence, you need to select it and create your shots.</p><p>For example, type sh0010 on the shots column, then again <strong>add</strong>. You can also define padding for your shots.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>If you want to name your shots ten on ten as SH0010, SH0020, SH0030, etc, set the <strong>Shot Padding</strong> as 10</p></div><p><img src="'+E+'" alt="Manage shots"></p><p>You can now see that new shots are listed and linked by their sequence. You have created the first shot of the first sequence.</p><p>Now, let&#39;s add more shots than just one! As you can see, the box already contains your name code but incremented, so you have to continue to click on <strong>add</strong> to create more shots.</p><p><img src="'+A+'" alt="Add shots"></p><p>To add more sequences, go to the left part, type the name of your new sequence, and then click on <strong>add</strong>. Your second sequence is selected, and you can now add shots.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>If a shot is misplaced on a sequence, you have to edit the shot <img src="'+e+'" alt="Edit button">, and change the sequence. <img src="'+n+'" alt="edit shot Change sequence"></p><p><img src="'+F+'" alt="Change sequence"></p></div><h2 id="create-shots-from-an-edl-file" tabindex="-1">Create Shots from an EDL File <a class="header-anchor" href="#create-shots-from-an-edl-file" aria-label="Permalink to “Create Shots from an EDL File”">​</a></h2><p>You may already have your shots list ready in an <strong>EDL</strong> file. With Kitsu, you can import your <strong>EDL</strong> file directly to create the sequence, shot, number of frames, Frame in and frame out, and more.</p><p>On the <strong>Global Shot Page</strong>, you will see an <strong>Import EDL</strong> button.</p><p><img src="'+M+'" alt="Import EDL Button"></p><p>You can select the naming convention of the video file used during the editing on the pop-up.</p><p><img src="'+O+'" alt="Import EDL Menu"></p><p>It means the video clip on the editing is named as project_sequence_shot.extension.</p><p>Here is an example of an EDL for the LGC production.</p><p><img src="'+L+'" alt="EDL Example"></p><p>The video files are named  LGC_100-000.mov, which means LGC is the production name, 100 is the sequence name, and 000 is the shot name.</p><p>You can import the EDL file once you are set with the naming convention.</p><p>Then click on <strong>Upload EDL</strong></p><p>Then Kitsu will create the shots.</p><p><img src="'+D+'" alt="EDL Shot creation"> :::</p><details class="details custom-block"><summary>Create Shots from a CSV Spreadsheet File</summary><p>You may already have your shots list ready in a spreadsheet file. With Kitsu, you have two ways to import them; the first is to import a <code>.csv</code> file directly, and the second is to copy-paste your data directly into Kitsu.</p><p>First, save your spreadsheet as a <code>.csv</code> file.</p><p>Then, return to the shot page on Kitsu and click the <strong>Import</strong> icon. <img src="'+t+'" alt="Import Icon"></p><p>A pop-up window <strong>Import data from a CSV</strong> opens. Click on <strong>Browse</strong> to pick your <code>.csv</code> file.</p><p><img src="'+K+'" alt="Import csv file"></p><p>To see the result, click on the <strong>Preview</strong> button.   You can check and adjust the name of the columns by previewing your data.   NB: the <strong>Episode</strong> column is only mandatory for a <strong>TV Show</strong> production.   <img src="'+i+'" alt="Import data copy paste data"></p><p>Once everything is good, click the <strong>Confirm</strong> button to import your data into Kitsu.</p><p>Now, all your shots are imported into Kitsu, and the task is created according to your <strong>Settings</strong>.</p><p><img src="'+o+'" alt="Import data copy paste data"></p></details><details class="details custom-block"><summary>Create Shots by Copying / Pasting a Spreadsheet File</summary><p>Open your spreadsheet, select your data, and copy them.</p><p><img src="'+r+'" alt="Import copy data"></p><p>Then, go back to the shot page on Kitsu and click on the <strong>Import</strong> icon <img src="'+t+'" alt="Import Icon">.</p><p>A pop-up window <strong>Import data from a CSV</strong> opens; click on the <strong>Paste a CSV data</strong> tab.</p><p><img src="'+l+'" alt="Import data copy paste tab">   You can paste your previously selected data and see the result with the <strong>Preview</strong> button.   <img src="'+p+'" alt="Import data copy paste data">   You can check and adjust the name of the columns by previewing your data.   NB: the <strong>Episode</strong> column is only mandatory for a <strong>TV Show</strong> production.   <img src="'+i+'" alt="Import data copy paste data"></p><p>Once everything is good, click the <strong>Confirm</strong> button to import your data into Kitsu.</p><p>Now, all your shots are imported into Kitsu, and the task is created according to your <strong>Settings</strong>.</p><p><img src="'+o+'" alt="Import data copy paste data"></p></details><h3 id="see-the-details-of-a-shot" tabindex="-1">See the Details of a Shot <a class="header-anchor" href="#see-the-details-of-a-shot" aria-label="Permalink to “See the Details of a Shot”">​</a></h3><p>If you want to see the details of a shot, click on its name.</p><p><img src="'+G+'" alt="Shot detail"></p><p>A new page opens with the list of the tasks, the assignation, and the status newsfeed on the right. You can navigate through each by clicking on the name of the tabs.</p><p><img src="'+V+'" alt="Shot detail page"></p><p>You can click on the status of each task to open the comment panel and see the history of the comments and the different versions.</p><p><img src="'+W+'" alt="Shot detail page"></p><p>You can also access the <strong>Casting</strong>,</p><p><img src="'+R+'" alt="Asset detail casting"></p><p>The <strong>Schedule</strong> is available if you have previously filled out the task type page data. If the data have already been filled out, you will be able to modify them directly here.</p><p><img src="'+B+'" alt="Asset detail casting"></p><p>the <strong>Preview Files</strong> uploaded at various task types,</p><p><img src="'+H+'" alt="Asset detail casting"></p><p>And the <strong>Timelog</strong> if people have filled out their timesheet on the tasks of this asset.</p><p><img src="'+z+'" alt="Asset detail casting"></p><h2 id="add-more-tasks-after-creating-the-shots" tabindex="-1">Add more tasks after creating the shots <a class="header-anchor" href="#add-more-tasks-after-creating-the-shots" aria-label="Permalink to “Add more tasks after creating the shots”">​</a></h2><p>If you realize after creating the shots that the task is missing, you can still add them.</p><p>First, be sure that the missing task type is added to the settings page under the task type tab.</p><p>Then go back to the shot page and click on + Add tasks.</p><h3 id="update-your-shots" tabindex="-1">Update your shots <a class="header-anchor" href="#update-your-shots" aria-label="Permalink to “Update your shots”">​</a></h3><p>You can update your shots at any point, change their names and sequences, modify their descriptions, and add any custom information you added to the global page.</p><p>You can edit shots by going to the shot page, hovering over the shot you want to modify, and then clicking on the <strong>edit</strong> button <img src="'+e+'" alt="Edit button"> (1) on the right side of the line.</p><p><img src="'+U+'" alt="Edit an asset"></p><p>To extend the description on the main shot page, click on the first words (2), and a pop-up with the full description will open.</p><details class="details custom-block"><summary>Update Shots Information with CSV Import</summary><p>You can use the <strong>CSV Import</strong> to update your data as the <strong>NB Frames</strong>, <strong>Frame IN</strong>, <strong>Frame Out</strong>, or any custom <strong>Metadata column</strong>.</p><p>You can update the <strong>Assignation</strong> , and the <strong>Status</strong> of tasks and add a <strong>Comment</strong>.</p><p>Open your spreadsheet, select your data, and copy them.</p><p><img src="'+r+'" alt="Import copy data"></p><p>Then, go back to the shot page on Kitsu and click on the <strong>Import</strong> icon <img src="'+t+'" alt="Import Icon">.</p><p>A pop-up window <strong>Import data from a CSV</strong> opens; click on the <strong>Paste a CSV data</strong> tab.</p><p><img src="'+l+'" alt="Import data copy paste tab">   You can paste your previously selected data and see the result with the <strong>Preview</strong> button.   <img src="'+p+'" alt="Import data copy paste data">   You need to switch on the <strong>Option: Update existing data</strong>. The updated shots will be in blue</p><p>NB: the <strong>Episode</strong> column is only mandatory for a <strong>TV Show</strong> production.   <img src="'+j+'" alt="Import data copy paste data"></p><p>Once everything is good, click the <strong>Confirm</strong> button to import your data into Kitsu.</p><p>Now, all your shots are imported into Kitsu, and the task is created according to your <strong>Settings</strong>.</p><p><img src="'+o+'" alt="Import data copy paste data"></p></details><h2 id="add-the-number-of-frames-and-frame-ranges-to-the-shots" tabindex="-1">Add the number of Frames and Frame ranges to the shots <a class="header-anchor" href="#add-the-number-of-frames-and-frame-ranges-to-the-shots" aria-label="Permalink to “Add the number of Frames and Frame ranges to the shots”">​</a></h2><p>At this stage of the Production, the animatic should be done. This means you have the length (<strong>number of frames</strong>, <strong>Frame range In</strong>, and <strong>Frame range Out</strong>) for each shot. You can add this information to the spreadsheet. This way, you are sure that all the frames are calculated and none are missing or over-computed.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>If you have created your shots and sequence by hand, the <strong>Frame</strong> column will be hidden. You must edit at least one shot and fill in the number of frames to display the <strong>Frame</strong> column. The column will be displayed if you have created your shots and imported the number of frames with a CSV/spreadsheet.</p></div><p>You need to edit the shots to fill in the frame range information. Click on the edit button <img src="'+e+'" alt="Edit button"> on the right side of the shot line.</p><p><img src="'+n+'" alt="edit shot Change sequence"></p><p>On the new window, you can enter the shots <strong>In</strong> and <strong>Out</strong>. Then, save by clicking the <strong>Confirm</strong> button.</p><p><img src="'+$+'" alt="Shot edit page"></p><p>Now, the frame range appears on the general spreadsheet of the shot page.</p><p><img src="'+J+'" alt="Shot edit page"></p><p>Now that you have unlocked the <strong>Frames</strong>, <strong>In</strong>, and <strong>Out</strong> columns, you can fill them directly from the global shot page.</p><p>Click on the case you want to fill in and add the data.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>If you enter the <strong>Frame In</strong> and <strong>Frame Out</strong>, Kitsu automatically calculates the <strong>Number of Frame</strong>.</p></div><p><img src="'+X+'" alt="Shot edit page"></p><p>You can also use the <strong>CSV Import</strong> to update your frame range quickly.  <a href="#update-your-shots">Update Shots information with CSV Import</a></p><p>You can also access the history of shot values.</p><p><img src="'+Q+'" alt="Shot framerange detail"></p><p><img src="'+Z+'" alt="Shot Values History"></p><h2 id="create-custom-metadata-columns" tabindex="-1">Create Custom Metadata Columns <a class="header-anchor" href="#create-custom-metadata-columns" aria-label="Permalink to “Create Custom Metadata Columns”">​</a></h2><p>To add more information on the general spreadsheet pages, you must create a custom <strong>metadata column</strong>.</p><p>You may have extra information to add to your pages, such as the <strong>level of difficulties</strong>, <strong>Weather</strong>, <strong>Tag</strong>, etc. You can store all text (or number) information in the custom metadata column.</p><p>Click on the <strong>+</strong> near the Name column.</p><p><img src="'+s+'" alt="Metadata Column"></p><p>With the <strong>Type</strong> option, you can choose how you want to store your information:</p><ul><li>a free <strong>Text</strong>,</li><li>a <strong>Number</strong>,</li><li>a <strong>Checkbox</strong>,</li><li>a <strong>List of value</strong>,</li><li>a <strong>List of tags</strong>,</li><li>a <strong>Checklist</strong>.</li></ul><p><img src="'+tt+'" alt="Metadata Column detail"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>The <strong>Text</strong>, <strong>Number</strong>, and <strong>Checkbox</strong> allow you to add different information for each entity. You don&#39;t have to plan it first.</p><p>The <strong>List of value</strong>, <strong>List of tags</strong>, and <strong>Checklist</strong> give you the same choice for each entity. Moreover, it has to be filled now.</p><p><img src="'+et+'" alt="Metadata Column list"></p><p>Type the list elements below <strong>Available values</strong>, and confirm them by clicking on <strong>Add value</strong>.</p></div><p>You can also link the <strong>metadata column</strong> to one or several <strong>departments</strong>.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Link a metadata column to a department. The artists/supervisors will see it on their to-do page and in the department-filtered view.</p><p>You can link the metadata column to one or more departments. Click on the department from the list and then click on <strong>add</strong> to be effective.</p><p>Here, the VFX column is linked to two departments.</p><p><img src="'+ot+'" alt="Department metadata column filtered view"></p></div><details class="details custom-block"><summary>Edit meta column</summary><p>On the global page of the asset or the shot, click on the arrow on the direct right of your metadata column and click on <strong>Edit</strong>.</p><p><img src="'+at+'" alt="Metadata column Edit"></p></details><p>You can fill in this information directly on the global spreadsheets page. The cases are editable.</p><p><img src="'+st+'" alt="Metadata Column detail"></p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>You can batch-modify the metadata column by selecting several entities on the left and then modifying your metadata column.</p></div><details class="details custom-block"><summary>Edit by hand</summary><p>You can also modify the information with the edit button <img src="'+e+'" alt="Edit button">.</p><p>You now see a new line on the edit pop-up. You can select the information from the list, alternatively, enter the free text or number, check a box, or use the checklist, depending on your previous choice.</p><p>Remember to press the <strong>Confirm</strong> button when you are done.</p><p><img src="'+nt+'" alt="Metadata Column detail"></p></details><p>Go to the general spreadsheet page if you need to edit or delete the metadata column. Nearby the name of your metadata column, click on the arrow <img src="'+it+'" alt="Metadata Column detail">.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>You can <strong>sort</strong> your global page with this new column. Click the arrow on the right of the column name to open his menu. Then click on <strong>Sort By</strong>.</p><p>You can also <strong>Stick</strong> the metadata column to the left.</p></div><h2 id="create-a-sequence" tabindex="-1">Create a Sequence <a class="header-anchor" href="#create-a-sequence" aria-label="Permalink to “Create a Sequence”">​</a></h2><p>In Kitsu, you can also track tasks at the <strong>Sequence</strong> Level. It&#39;s especially useful when you have macro tasks to track, like Story and color Board, Color Grading, etc.</p><p>Use the navigation menu to go to the <strong>Sequences</strong> page.</p><p><img src="'+rt+'" alt="Navigation Sequences"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>This new page behaves like the asset and shot global page.</p><p>To use this page, You first need to create dedicated task types on your <strong>Global Library</strong>  with the <strong>Sequence</strong> attribute.</p><p>See the <strong>Creating a New Task Type</strong> Section to create a new <strong>Task Type</strong>.</p><p><a href="./../configure-kitsu/index.html#task-types">Creating a New Task Type</a></p><p>Once you have created your <strong>Task Types</strong>  on your <strong>Global Library</strong>, add them to your <strong>Production Library</strong> (setting page).</p></div><p>Once your task types are ready on the settings page, you need to create a sequence (the same as the assets or shots).</p><p>This new page behaves like the asset and shot global page. You can add your edits with the <strong>+ New Sequence</strong> button.</p><p>You can assign tasks, do the review, change status, etc.</p><p>You can add a metadata column, fill in the description, etc.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>You can create a sequence directly from here (+New sequence button) or create a sequence linked to your shots from the global shot page.</p></div><p>You can <strong>Rename</strong> and <strong>Delete</strong> the Sequence entity on this page, as for the asset and shot entity.</p><p>If you click on the name of a sequence, you will see the detail page of this sequence.</p><p><img src="'+lt+'" alt="Sequence detailed page"></p><p>On the detailed page, you have access to the sequence casting. You can see all the assets used in the whole sequence.</p><p>You can also access the schedule, Preview Files, Activity, and Timelog of the sequence <strong>tasks</strong>.</p><h2 id="create-an-edit" tabindex="-1">Create an Edit <a class="header-anchor" href="#create-an-edit" aria-label="Permalink to “Create an Edit”">​</a></h2><p>You can track tasks at the <strong>Edit</strong> Level in Kitsu.</p><p>It&#39;s especially useful when You have several edits to track through several validation steps. For example, you can track your whole movie, several trailers, and the First Edit, Fine Edit, Mix, etc.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Per default, the <strong>Edit</strong> page will not be displayed until you have task types for it on your <strong>production library</strong> (setting page)</p></div><p>To use this page, you need to first create a dedicated task type on your <strong>Global Library</strong>  with the <strong>Edit</strong> attribute.</p><p>See the <strong>Creating a New Task Type</strong> Section to create a new <strong>Task Type</strong>.</p><p><a href="./../configure-kitsu/index.html#task-types">Creating a New Task Type</a></p><p>Once you have created your <strong>Task Types</strong>  on your <strong>Global Library</strong>, add them to your <strong>Production Library</strong>, you will see the <strong>Edit</strong> displayed on the navigation drop-down menu.</p><p><img src="'+pt+'" alt="Navigation Edit"></p><p>This new page behaves like the asset and shot global page. You can add your edits with the <strong>+ New edit</strong> button.</p><p>You can assign tasks, do the review, change status, etc.</p><p>You can add a metadata column, fill in the description, etc.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Depending on your deliveries, you can also change the resolution per <strong>Edit</strong>.</p></div><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>The detail page is different from the other entities.</p><p>As <strong>Edit</strong> focuses on a specific long video, the detail page looks more like the comment detail page.</p></div><p>You can <strong>Rename</strong> and <strong>Delete</strong> the Edit entity on this page for the asset and shot entity.</p>',191)])])}const kt=c(ct,[["render",ht]]);export{bt as __pageData,kt as default};
